1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_PERCENT = 10;
3	
4	interface Item {
5	  type: string;
6	}
7	interface QuoteStep {
8	  op: "quote";
9	  items: Item[];
10	}
11	interface Scenario {
12	  customer: { yearsWithMHPCO: number };
13	  steps: QuoteStep[];
14	}
15	
16	const BASE_PREMIUM: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	};
22	
23	// Rounds up in MHPCO's favor; integer arithmetic avoids IEEE 754 drift.
24	const applyPercentSurchargeRoundedUp = (base: number, percent: number): number =>
25	  Math.ceil((base * (100 + percent)) / 100);
26	
27	const quotePremium = (step: QuoteStep): number => {
28	  const [firstItem] = step.items;
29	  if (firstItem === undefined) return PROCESSING_FEE;
30	  const itemBase = BASE_PREMIUM[firstItem.type];
31	  const withFirstInsurance = applyPercentSurchargeRoundedUp(itemBase, FIRST_INSURANCE_SURCHARGE_PERCENT);
32	  return withFirstInsurance + PROCESSING_FEE;
33	};
34	
35	export const processScenario = (scenario: Scenario): unknown => {
36	  const results = scenario.steps.map((step) => ({ premium: quotePremium(step) }));
37	  return { results };
38	};
